import{_ as e,o,c as d,ag as a}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"스킬 생성","description":"SKILL.md로 커스텀 워크스페이스 스킬 개발 및 테스트","frontmatter":{"title":"스킬 생성","description":"SKILL.md로 커스텀 워크스페이스 스킬 개발 및 테스트"},"headers":[],"relativePath":"tools/creating-skills.md","filePath":"tools/creating-skills.md","lastUpdated":null}'),l={name:"tools/creating-skills.md"};function r(n,t,s,i,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="스킬-생성" tabindex="-1">스킬 생성 <a class="header-anchor" href="#스킬-생성" aria-label="Permalink to &quot;스킬 생성&quot;">​</a></h1><p>스킬은 에이전트에게 도구를 사용하는 방법과 시기를 가르칩니다. 각 스킬은 YAML 프론트매터와 마크다운 지침이 있는 <code>SKILL.md</code> 파일이 들어 있는 디렉토리입니다.</p><p>스킬이 로드되고 우선순위가 결정되는 방법에 대해서는 <a href="/openclaw-docs-ko/tools/skills">스킬</a>을 참조하십시오.</p><h2 id="첫-번째-스킬-만들기" tabindex="-1">첫 번째 스킬 만들기 <a class="header-anchor" href="#첫-번째-스킬-만들기" aria-label="Permalink to &quot;첫 번째 스킬 만들기&quot;">​</a></h2><ol><li><p><strong>스킬 디렉토리 생성</strong></p><p>스킬은 워크스페이스에 저장됩니다. 새 폴더를 생성합니다:</p><pre><code>```bash\nmkdir -p ~/.openclaw/workspace/skills/hello-world\n```\n</code></pre></li><li><p><strong>SKILL.md 작성</strong></p></li></ol><p>해당 디렉토리 안에 <code>SKILL.md</code>를 생성합니다. 프론트매터는 메타데이터를 정의하고, 마크다운 본문은 에이전트에 대한 지침을 담습니다.</p><pre><code>   ```markdown\n   ---\n   name: hello_world\n   description: A simple skill that says hello.\n   ---\n\n   # Hello World Skill\n\n   When the user asks for a greeting, use the `echo` tool to say\n   &quot;Hello from your custom skill!&quot;.\n   ```\n</code></pre><ol start="3"><li><strong>도구 추가 (선택 사항)</strong></li></ol><p>프론트매터에서 커스텀 도구 스키마를 정의하거나 에이전트가 기존 시스템 도구(<code>exec</code> 또는 <code>browser</code> 등)를 사용하도록 지시할 수 있습니다. 스킬은 또한 플러그인 내부에서 문서화하는 도구와 함께 제공될 수 있습니다.</p><ol start="4"><li><strong>스킬 로드</strong></li></ol><p>OpenClaw가 스킬을 가져올 수 있도록 새 세션을 시작합니다:</p><pre><code>   ```bash\n   # 채팅에서\n   /new\n\n   # 또는 게이트웨이 재시작\n   openclaw gateway restart\n   ```\n\n   스킬이 로드되었는지 확인합니다:\n\n   ```bash\n   openclaw skills list\n   ```\n</code></pre><ol start="5"><li><strong>테스트</strong></li></ol><p>스킬을 트리거해야 하는 메시지를 보냅니다:</p><pre><code>   ```bash\n   openclaw agent --message &quot;give me a greeting&quot;\n   ```\n\n   또는 에이전트와 채팅하여 인사를 요청합니다.\n</code></pre><h2 id="스킬-메타데이터-레퍼런스" tabindex="-1">스킬 메타데이터 레퍼런스 <a class="header-anchor" href="#스킬-메타데이터-레퍼런스" aria-label="Permalink to &quot;스킬 메타데이터 레퍼런스&quot;">​</a></h2><p>YAML 프론트매터는 다음 필드를 지원합니다:</p><table tabindex="0"><thead><tr><th>필드</th><th>필수 여부</th><th>설명</th></tr></thead><tbody><tr><td><code>name</code></td><td>예</td><td>고유 식별자 (snake_case)</td></tr><tr><td><code>description</code></td><td>예</td><td>에이전트에게 표시되는 한 줄 설명</td></tr><tr><td><code>metadata.openclaw.os</code></td><td>아니오</td><td>OS 필터 (<code>[&quot;darwin&quot;]</code>, <code>[&quot;linux&quot;]</code> 등)</td></tr><tr><td><code>metadata.openclaw.requires.bins</code></td><td>아니오</td><td>PATH에 있어야 하는 바이너리</td></tr><tr><td><code>metadata.openclaw.requires.config</code></td><td>아니오</td><td>필수 설정 키</td></tr></tbody></table><h2 id="모범-사례" tabindex="-1">모범 사례 <a class="header-anchor" href="#모범-사례" aria-label="Permalink to &quot;모범 사례&quot;">​</a></h2><ul><li><strong>간결하게</strong> — 모델에게 AI가 되는 방법이 아니라 <em>무엇을</em> 해야 하는지 지침을 제공합니다</li><li><strong>안전 우선</strong> — 스킬이 <code>exec</code>를 사용하는 경우 프롬프트가 신뢰할 수 없는 입력으로 임의 명령 삽입을 허용하지 않도록 합니다</li><li><strong>로컬 테스트</strong> — 공유하기 전에 <code>openclaw agent --message &quot;...&quot;</code>로 테스트합니다</li><li><strong>ClawHub 사용</strong> — <a href="https://clawhub.ai" target="_blank" rel="noreferrer">ClawHub</a>에서 스킬을 탐색하고 기여합니다</li></ul><h2 id="스킬-저장-위치" tabindex="-1">스킬 저장 위치 <a class="header-anchor" href="#스킬-저장-위치" aria-label="Permalink to &quot;스킬 저장 위치&quot;">​</a></h2><table tabindex="0"><thead><tr><th>위치</th><th>우선순위</th><th>범위</th></tr></thead><tbody><tr><td><code>\\&lt;workspace\\&gt;/skills/</code></td><td>최고</td><td>에이전트별</td></tr><tr><td><code>\\&lt;workspace\\&gt;/.agents/skills/</code></td><td>높음</td><td>워크스페이스 에이전트별</td></tr><tr><td><code>~/.agents/skills/</code></td><td>중간</td><td>공유 에이전트 프로파일</td></tr><tr><td><code>~/.openclaw/skills/</code></td><td>중간</td><td>공유 (모든 에이전트)</td></tr><tr><td>번들 (OpenClaw와 함께 제공)</td><td>낮음</td><td>전역</td></tr><tr><td><code>skills.load.extraDirs</code></td><td>최저</td><td>커스텀 공유 폴더</td></tr></tbody></table><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/skills">스킬 레퍼런스</a> — 로드, 우선순위, 게이팅 규칙</li><li><a href="/openclaw-docs-ko/tools/skills-config">스킬 설정</a> — <code>skills.*</code> 설정 스키마</li><li><a href="/openclaw-docs-ko/tools/clawhub">ClawHub</a> — 공개 스킬 레지스트리</li><li><a href="/openclaw-docs-ko/plugins/building-plugins">플러그인 개발</a> — 플러그인에 스킬 포함 가능</li></ul>',24)])])}const g=e(l,[["render",r]]);export{u as __pageData,g as default};
